import * as vscode from "vscode";

export function createDiagnostic(diagnostics:vscode.Diagnostic[],message: string, offset: number,document: vscode.TextDocument): void {
    const range = new vscode.Range(document.positionAt(offset),document.positionAt(offset!+1));
    const diagnostic = new vscode.Diagnostic(range, message, vscode.DiagnosticSeverity.Error);
    if (!diagnostics.includes(diagnostic)){
    diagnostics.push(diagnostic);}
}